RenderScript.Source:
                    import org.apache.log4j.Logger;
                    import sailpoint.object.AuditEvent;
                    import sailpoint.object.Identity;
                    import sailpoint.object.Filter;
                    import sailpoint.tools.Util;

                    Logger logger = Logger.getLogger("sailpoint.ascension.task");

                    logger.debug("##################### HFM Attestation Live Report starts ##################### ");
										renderCache.clear();
                    logger.debug("#####################  renderCache.clear() = " +  renderCache);

                    AuditEvent event = context.getObjectById(AuditEvent.class, value);
                    if(null != event)
                    {
                      logger.debug("HFM || ##################### event = " +  event.toXml());
                      renderCache.put("actionStatus", event.getAttribute("actionStatus"));
                      renderCache.put("certificationOwner", event.getAttribute("certificationOwner"));
                      renderCache.put("certifierDisplayName", event.getAttribute("certifierDisplayName"));
                      renderCache.put("certifierEmail", event.getAttribute("certifierEmail"));
                      renderCache.put("certifierEmployeeId", event.getAttribute("certifierEmployeeId"));
                      renderCache.put("entitlementValue", event.getAttribute("entitlementValue"));
                      renderCache.put("targetUserDisplayName", event.getAttribute("targetUserDisplayName"));
                      renderCache.put("targetUserId", event.getAttribute("targetUserId"));
                    	renderCache.put("application", event.getApplication());
                      String targetUserSAMAccName = event.getAttribute("targetUserSAMAccName");
                      renderCache.put("targetUserSAMAccName", targetUserSAMAccName);
                      if(Util.isNotNullOrEmpty(targetUserSAMAccName))
                      {
                        Identity targetIden = context.getUniqueObject(Identity.class, Filter.eq("samAccountName" , targetUserSAMAccName));
                        Identity managerIden = null;
                        if(null != targetIden)
                        {
                          managerIden = targetIden.getManager();
                          renderCache.put("targetUserLocation", targetIden.getStringAttribute("location"));
                          renderCache.put("targetUserDepartment", targetIden.getStringAttribute("department"));
                          renderCache.put("targetUserTitle", targetIden.getStringAttribute("title"));
                        }
                        if(null != managerIden)
                        {
                          if(Util.isNotNullOrEmpty(managerIden.getStringAttribute("displayName")))
                           renderCache.put("managerDisplayName", managerIden.getStringAttribute("displayName"));
                          else
                            renderCache.put("managerDisplayName", managerIden.getStringAttribute("lastname") +", "+ managerIden.getStringAttribute("firstname"));
                        }
                        else
                          renderCache.put("managerDisplayName", "Manager not found in IIQ");
                      }
                      renderCache.put("certifierPhone", event.getAttribute("certifierPhone"));
                      renderCache.put("certifierMinistry", event.getAttribute("certifierMinistry"));
                      renderCache.put("targetUserMinistry", event.getAttribute("targetUserMinistry"));
                    }
										logger.debug("#####################  renderCache = " +  renderCache);
                    return renderCache.get("application");
